SELECT u.id, u.name, u.username, u.email, u.id_num, r.id AS role_id, r.name AS role_name, m.id AS merchant_id, m.name AS merchant_name, u.status, u.create_time FROM user u LEFT JOIN user_role ur ON u.id = ur.user_id AND ur.is_delete = 0 LEFT JOIN role r ON ur.role_id = r.id AND r.is_delete = 0 LEFT JOIN merchant m ON u.merchant_id = m.id AND m.is_delete = 0
u.is_delete = 0 AND r.name != 'admin' AND r.name != '出单员'
AND (u.name LIKE CONCAT('%', #{blurParam}, '%') OR u.username LIKE CONCAT('%', #{blurParam}, '%'))
AND m.id = #{merchantId}
AND r.id = #{roleId}
AND u.status = #{status}

SELECT u.id, u.name, u.username, u.email, u.id_num, r.id AS role_id, r.name AS role_name, u.status, u.create_time FROM user u LEFT JOIN user_role ur ON u.id = ur.user_id AND ur.is_delete = 0 LEFT JOIN role r ON ur.role_id = r.id AND r.is_delete = 0
u.is_delete = 0 AND (r.name = 'admin' OR r.name = '出单员') AND u.is_approval = 1
AND (u.name LIKE CONCAT('%', #{blurParam}, '%') OR u.username LIKE CONCAT('%', #{blurParam}, '%'))
AND r.id = #{roleId}
AND u.status = #{status}
